    "citationBibtex": "@article{Teissier2020long-term-persistenc,\n  title={Long-term persistence of monotypic dengue transmission in small size isolated populations, French Polynesia, 1978-2014},\n  author={Teissier, Yoann and Paul, Richard and Aubry, Maite and Rodo, Xavier and Dommar, Carlos and Salje, Henrik and Sakuntabhai, Anavaj and Cazelles, Bernard and Cao-Lormeau, Van-Mai},\n  journal={PLOS Neglected Tropical Diseases},\n  year={2020},\n  doi={10.1371/journal.pntd.0008110},\n  url={https://doi.org/10.1371/journal.pntd.0008110}\n}",
